const ctx = $items('Finalize Analysis Context', 0, 0)?.[0]?.json || {};
const analysisId = Number(ctx.impact_analysis_id);
const analysis = (ctx.analysis && typeof ctx.analysis === 'object') ? ctx.analysis : {};
const impacts = analysis.impactos || analysis.impacts || {};

const impactedRepos = Object.entries(impacts)
  .filter(([, info]) => info && (info.impacto === true || info.impact === true || info.has_impact === true))
  .map(([repoName, info]) => {
    const changes = Array.isArray(info.mudancas) ? info.mudancas : [];
    return {
      repositorio: repoName,
      mudancas: changes
        .map((c) => String((c && (c.descricao || c.description)) || '').trim())
        .filter(Boolean),
      testes_sugeridos: changes
        .flatMap((c) => Array.isArray(c?.testes) ? c.testes : [])
        .map((t) => String(t || '').trim())
        .filter(Boolean)
    };
  });

const artifacts = impactedRepos.map((r) => ({
  repositorio: r.repositorio,
  artefatos: [
    'PR de implementacao no repositorio',
    'Diff real de codigo no PR',
    'Checklist de testes no corpo/arquivos da PR'
  ]
}));

const owner = String(ctx.owner || 'oliversoft-tech');
const repo = String(ctx.repo || 'fastroute-changemanagement');

return [{
  analysis_id: Number.isFinite(analysisId) ? analysisId : null,
  dispatch_status: 'queued',
  repos_impactados: impactedRepos.map((r) => r.repositorio),
  artefatos_previstos: artifacts,
  mudancas_previstas: impactedRepos,
  revisar_em: `https://github.com/${owner}/${repo}/actions`,
  mensagem: 'Governance disparado para gerar PRs por repositorio impactado. Revise os diffs reais nas PRs antes de aprovar.'
}];

