={{ (() => {
  const analysis = ($json.analysis && typeof $json.analysis === 'object') ? $json.analysis : {};
  const rawSummary = String(analysis.resumo || analysis.summary || 'Sem resumo').trim();
  const safeSummary = rawSummary
    .replace(/["'`]/g, '')
    .replace(/[()]/g, '')
    .replace(/\s+/g, ' ')
    .slice(0, 450);

  const payloadAnalysis = {
    ...analysis,
    resumo: safeSummary,
  };

  return JSON.stringify({
    event_type: 'governance-release',
    client_payload: {
      source_repo: 'fastroute-changemanagement',
      source_ref: 'main',
      domain_ref: $json.domain_ref || 'main',
      api_ref: $json.api_ref || 'main',
      mobile_ref: $json.mobile_ref || 'main',
      mobile_profile: $json.mobile_profile || 'preview',
      run_release: false,
      deploy_api: false,
      auto_implement: true,
      impact_analysis: payloadAnalysis
    }
  });
})() }}
